query.sparql:
SELECT ?answer
WHERE {
  ?answer wdt:P451 wd:Q4205826 .
  ?answer wdt:P451 wd:Q4463198 .
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?founder ?founderLabel
WHERE {
  wd:Q8797 wdt:P162 ?founder.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?author ?work ?workLabel
WHERE {
  wd:Q216332 wdt:P50 ?author.
  ?work wdt:P50 ?author.
  ?work rdfs:label ?workLabel.
  FILTER NOT EXISTS { ?work wdt:P50 wd:Q216332 }
}
